1	import { selectorWhereSql } from "../db";
2	import type { RawHitRow } from "../ranking";
3	import { hasCjk, queryTerms } from "../tokenize";
4	import type { Selector } from "../types";
5	import type { Db, SqlParams } from "../db";
6	import { makeLikeSnippet, makeRawSnippet } from "./snippet";
7	
8	export function searchMessageHits(
9	  db: Db,
10	  query: string,
11	  limit: number,
12	  sessionUuid?: string,
13	  selector: Selector | null = null,
14	): RawHitRow[] {
15	  const normalized = query.trim();
16	  if (!normalized) return [];
17	
18	  const terms = queryTerms(normalized);
19	  // Queries that degenerate to zero tokens (e.g. a single kanji dropped as
20	  // stop-word-like noise, or whitespace only) cannot hit the FTS index. Fall
21	  // back to a bounded LIKE scan so single-character CJK probes still work
22	  // even though they are discouraged.
23	  if (terms.length === 0) {
24	    if (hasCjk(normalized)) return searchByLike(db, normalized, limit, sessionUuid, selector);
25	    return [];
26	  }
27	
28	  return searchByFts(db, terms, limit, sessionUuid, selector);
29	}
30	
31	export function searchSessionHits(db: Db, query: string, limit: number, selector: Selector | null): RawHitRow[] {
32	  const normalized = query.trim();
33	  if (!normalized || !tableExists(db, "sessions_fts")) return [];
34	
35	  const terms = queryTerms(normalized);
36	  if (terms.length === 0) return [];
37	
38	  return searchSessionsByFts(db, normalized, terms, limit, selector);
39	}
40	
41	function searchByFts(
42	  db: Db,
43	  terms: string[],
44	  limit: number,
45	  sessionUuid?: string,
46	  selector: Selector | null = null,
47	): RawHitRow[] {
48	  const matchExpr = buildFtsMatch(terms);
49	  const conditions = [`messages_fts MATCH ?`];
50	  const params: SqlParams = [matchExpr];
51	
52	  if (selector) {
53	    const selectorWhere = selectorWhereSql(selector, "s");
54	    conditions.push(...selectorWhere.conditions);
55	    params.push(...selectorWhere.params);
56	  }
57	  if (sessionUuid) {
58	    conditions.push("m.session_uuid = ?");
59	    params.push(sessionUuid);
60	  }
61	  params.push(limit);
62	
63	  return db
64	    .prepare<typeof params, RawHitRow>(`
65	      SELECT
66	        s.session_uuid AS sessionUuid,
67	        s.title AS title,
68	        s.summary_text AS summaryText,
69	        s.cwd AS cwd,
70	        s.started_at AS startedAt,
71	        s.ended_at AS endedAt,
72	        'message' AS matchSource,
73	        m.seq AS matchSeq,
74	        m.role AS matchRole,
75	        m.timestamp AS matchTimestamp,
76	        m.content_text AS contentText,
77	        snippet(messages_fts, 0, '<mark>', '</mark>', '…', 16) AS snippet,
78	        bm25(messages_fts) AS score
79	      FROM messages_fts
80	      JOIN messages m ON m.id = messages_fts.rowid
81	      JOIN sessions s ON s.id = m.session_id
82	      WHERE ${conditions.join(" AND ")}
83	      ORDER BY score
84	      LIMIT ?
85	    `)
86	    .all(...params) as RawHitRow[];
87	}
88	
89	function searchSessionsByFts(
90	  db: Db,
91	  query: string,
92	  terms: string[],
93	  limit: number,
94	  selector: Selector | null,
95	): RawHitRow[] {
96	  const matchExpr = buildFtsMatch(terms);
97	  const conditions = ["sessions_fts MATCH ?"];
98	  const params: SqlParams = [matchExpr];
99	  if (selector) {
100	    const selectorWhere = selectorWhereSql(selector, "s");
101	    conditions.push(...selectorWhere.conditions);
102	    params.push(...selectorWhere.params);
103	  }
104	  params.push(limit);
105	  const rows = db
106	    .prepare<typeof params, RawHitRow>(`
107	      SELECT
108	        s.session_uuid AS sessionUuid,
109	        s.title AS title,
110	        s.summary_text AS summaryText,
111	        s.cwd AS cwd,
112	        s.started_at AS startedAt,
113	        s.ended_at AS endedAt,
114	        'session' AS matchSource,
115	        NULL AS matchSeq,
116	        'session' AS matchRole,
117	        NULL AS matchTimestamp,
118	        s.title || char(10) || s.summary_text || char(10) || s.compact_text || char(10) || s.reasoning_summary_text AS contentText,
119	        '' AS snippet,
120	        bm25(sessions_fts, 8.0, 3.0, 4.0, 1.2) AS score
121	      FROM sessions_fts
122	      JOIN sessions s ON s.id = sessions_fts.rowid
123	      WHERE ${conditions.join(" AND ")}
124	      ORDER BY score
125	      LIMIT ?
126	    `)
127	    .all(...params) as RawHitRow[];
128	
129	  return rows.map((row) => ({
130	    ...row,
131	    snippet: makeRawSnippet(row.contentText, query, terms),
132	  }));
133	}
134	
135	function searchByLike(
136	  db: Db,
137	  query: string,
138	  limit: number,
139	  sessionUuid?: string,
140	  selector: Selector | null = null,
141	): RawHitRow[] {
142	  const conditions = ["lower(m.content_text) LIKE ? ESCAPE '\\'"];
143	  const params: SqlParams = [`%${escapeLike(query.toLowerCase())}%`];
144	  if (selector) {
145	    const selectorWhere = selectorWhereSql(selector, "s");
146	    conditions.push(...selectorWhere.conditions);
147	    params.push(...selectorWhere.params);
148	  }
149	  if (sessionUuid) {
150	    conditions.push("m.session_uuid = ?");
151	    params.push(sessionUuid);
152	  }
153	  params.push(limit);
154	
155	  const rows = db
156	    .prepare<typeof params, RawHitRow & { contentText: string }>(`
157	      SELECT
158	        s.session_uuid AS sessionUuid,
159	        s.title AS title,
160	        s.summary_text AS summaryText,
161	        s.cwd AS cwd,
162	        s.started_at AS startedAt,
163	        s.ended_at AS endedAt,
164	        'message' AS matchSource,
165	        m.seq AS matchSeq,
166	        m.role AS matchRole,
167	        m.timestamp AS matchTimestamp,
168	        m.content_text AS contentText
169	      FROM messages m
170	      JOIN sessions s ON s.id = m.session_id
171	      WHERE ${conditions.join(" AND ")}
172	      ORDER BY s.started_at DESC, m.seq ASC
173	      LIMIT ?
174	    `)
175	    .all(...params) as Array<RawHitRow & { contentText: string }>;
176	
177	  return rows.map((row, index) => ({
178	    ...row,
179	    snippet: makeLikeSnippet(row.contentText, query),
180	    // Negate the ordinal so LIKE rows share the "lower is better" polarity
181	    // with bm25() scores; downstream rerank sorts on row metrics, but any
182	    // code that touches this raw score won't see a sign mismatch.
183	    score: -(index + 1),
184	  }));
185	}
186	
187	function tableExists(db: Db, tableName: string): boolean {
188	  const row = db
189	    .prepare<[string], unknown>("SELECT 1 FROM sqlite_master WHERE name = ? LIMIT 1")
190	    .get(tableName);
191	  return Boolean(row);
192	}
193	
194	/**
195	 * Build an FTS5 MATCH expression from already-tokenized terms. Each term is
196	 * quoted and ANDed, giving us intersection semantics across CJK bigrams and
197	 * non-CJK words alike.
198	 */
199	function buildFtsMatch(terms: string[]): string {
200	  return terms.map(quoteFtsTerm).join(" AND ");
201	}
202	
203	function quoteFtsTerm(term: string): string {
204	  // FTS5 treats unquoted * / ^ / NEAR / NOT / AND / OR as operators. Wrapping
205	  // each term in double quotes neutralizes all of them (including *), and we
206	  // escape internal quotes by doubling them. Bigrams stay bigrams.
207	  const escaped = term.replaceAll('"', '""');
208	  return `"${escaped}"`;
209	}
210	
211	// LIKE-path escape stays unchanged: only CJK single-character probes and
212	// empty-token queries fall through to this branch now.
213	function escapeLike(value: string): string {
214	  return value.replaceAll("\\", "\\\\").replaceAll("%", "\\%").replaceAll("_", "\\_");
215	}
216

