6	
7	export function getMessageRange(
8	  dbPath: string,
9	  sessionUuid: string,
10	  options: { seq?: number; query?: string; before: number; after: number },
11	): {
12	  session: SessionRecord;
13	  anchorSeq: number;
14	  rangeStartSeq: number;
15	  rangeEndSeq: number;
16	  messages: ReturnType<typeof getMessagesForRange>;
17	  coverage: { entries: ReturnType<typeof coverageEntriesForSession> };
18	} {
19	  return withReadDb(dbPath, (db) => {
20	    const anchorSeq = resolveAnchorSeq(db, sessionUuid, options.seq, options.query);
21	    const session = getSessionRecord(db, sessionUuid);
22	    if (!session) throw new Error(`session not found: ${sessionUuid}`);
23	
24	    const rangeStartSeq = Math.max(0, anchorSeq - options.before);
25	    const rangeEndSeq = anchorSeq + options.after;
26	    const messages = getMessagesForRange(db, sessionUuid, rangeStartSeq, rangeEndSeq);
27	    return {
28	      session,
29	      anchorSeq,
30	      rangeStartSeq,
31	      rangeEndSeq,
32	      messages,
33	      coverage: { entries: coverageEntriesForSession(db, session) },
34	    };
35	  });
36	}
