38	export function getMessagePage(
39	  dbPath: string,
40	  sessionUuid: string,
41	  offset: number,
42	  limit: number,
43	): {
44	  session: SessionRecord;
45	  offset: number;
46	  limit: number;
47	  totalCount: number;
48	  hasMore: boolean;
49	  messages: ReturnType<typeof getMessagesForPage>;
50	  coverage: { entries: ReturnType<typeof coverageEntriesForSession> };
51	} {
52	  return withReadDb(dbPath, (db) => {
53	    const session = getSessionRecord(db, sessionUuid);
54	    if (!session) throw new Error(`session not found: ${sessionUuid}`);
55	    const messages = getMessagesForPage(db, sessionUuid, offset, limit);
56	    const totalCount = session.messageCount;
57	    const hasMore = offset + messages.length < totalCount;
58	    return {
59	      session,
60	      offset,
61	      limit,
62	      totalCount,
63	      hasMore,
64	      messages,
65	      coverage: { entries: coverageEntriesForSession(db, session) },
66	    };
67	  });
68	}
69	
70	function resolveAnchorSeq(
71	  db: Db,
72	  sessionUuid: string,
73	  seq?: number,
74	  query?: string,
75	): number {
76	  if (typeof seq === "number") {
77	    return seq;
78	  }
79	
80	  if (query) {
81	    const best = searchTopHitInSession(db, sessionUuid, query);
82	    if (best && typeof best.matchSeq === "number") return best.matchSeq;
83	  }
84	
85	  throw new Error("read-range requires explicit session_uuid plus either --seq or --query");
86	}
