88	function searchTopHitInSession(db: Db, sessionUuid: string, query: string): FindResult | null {
89	  const rows = searchMessageHits(db, query, 20, sessionUuid);
90	  const result = rerankHits(rows, query, 1)[0];
91	  return result ?? null;
92	}
