import { DEFAULT_DB_PATH, INDEX_VERSION, ensureDataDir, resolveCodexDir } from "./env";
import {
  countSessionsForSelector,
  deleteSessionsForSelectorExceptFilePaths,
  deleteSessionByFilePath,
  getIndexedSessionMeta,
  openWriteDb,
  replaceCoverage,
  replaceSession,
} from "./db";
import { parseCodexSession } from "./parser";
import { canonicalizeSelector } from "./selector";
import { collectSourceSnapshot } from "./source-inventory";
import { withSyncLock } from "./sync-lock";
import type { CoverageWriteSummary, ParsedSession, Selector, SyncErrorDetail, SyncSummary } from "./types";

interface SyncOptions {
  dbPath?: string;
  rootDir?: string;
  selector?: Selector;
  bestEffort?: boolean;
}

type SyncOperation =
  | {
      kind: "replace";
      filePath: string;
      session: ParsedSession;
      rawFileMtime: number;
      rawFileSize: number;
      pathDate: string;
      isUpdate: boolean;
    }
  | {
      kind: "filtered";
      filePath: string;
    };

export class SyncError extends Error {
  summary: SyncSummary;

  constructor(summary: SyncSummary) {
    super(buildSyncErrorMessage(summary));
    this.name = "SyncError";
    this.summary = summary;
  }
}

export async function syncSessions(options: SyncOptions = {}): Promise<SyncSummary> {
  ensureDataDir();
  const dbPath = options.dbPath ?? DEFAULT_DB_PATH;
  const selector = canonicalizeSelector(options.selector ?? { kind: "all", root: resolveCodexDir(options.rootDir) });
  return withSyncLock(dbPath, async () => {
    const db = openWriteDb(dbPath);
    const sourceSnapshot = collectSourceSnapshot(selector);
    const operations: SyncOperation[] = [];
    const unchangedFilePaths = new Set<string>();

    const summary: SyncSummary = {
      scanned: sourceSnapshot.fileCount,
      added: 0,
      updated: 0,
      skipped: 0,
      filtered: 0,
      removed: 0,
      errors: 0,
      errorDetails: [],
      selector,
      coverage: skippedCoverage(selector, sourceSnapshot.fingerprint, sourceSnapshot.fileCount, "not_written"),
    };

    try {
      for (const file of sourceSnapshot.files) {
        const filePath = file.filePath;
        try {
          const indexed = getIndexedSessionMeta(db, filePath);
          if (isUnchanged(indexed, file.mtimeMs, file.size)) {
            summary.skipped += 1;
            unchangedFilePaths.add(filePath);
            continue;
          }

          const parsed = await parseCodexSession(filePath);
          if (parsed.kind === "filtered") {
            operations.push({ kind: "filtered", filePath });
            continue;
          }
          if (parsed.kind === "skipped") {
            summary.skipped += 1;
            continue;
          }

          operations.push({
            kind: "replace",
            filePath,
            session: parsed.session,
            rawFileMtime: file.mtimeMs,
            rawFileSize: file.size,
            pathDate: file.pathDate ?? "",
            isUpdate: Boolean(indexed),
          });
        } catch (error) {
          recordSyncError(summary, filePath, error);
        }
      }

      if (summary.errors > 0 && !options.bestEffort) {
        throw new SyncError(summary);
      }

      if (!options.bestEffort) {
        const afterSnapshot = collectSourceSnapshot(selector);
        if (afterSnapshot.fingerprint !== sourceSnapshot.fingerprint) {
          recordSyncError(summary, "(selector)", new Error("source changed during strict sync"));
          throw new SyncError(summary);
        }
      }

      const bestEffort = Boolean(options.bestEffort);
      const retainedFilePaths = retainedIndexedFilePaths(unchangedFilePaths, operations);
      summary.coverage = applyOperations(
        db,
        operations,
        summary,
        bestEffort,
        selector,
        sourceSnapshot,
        retainedFilePaths,
      );
      if (summary.errors > 0 && !options.bestEffort) {
        throw new SyncError(summary);
      }

      return summary;
    } finally {
      db.close();
    }
  });
}

function isUnchanged(
  indexed: { rawFileMtime: number; rawFileSize: number; indexVersion: string } | null,
  mtimeMs: number,
  size: number,
): boolean {
  if (!indexed) return false;
  return indexed.rawFileMtime === mtimeMs
    && indexed.rawFileSize === size
    && indexed.indexVersion === INDEX_VERSION;
}

function applyOperations(
  db: ReturnType<typeof openWriteDb>,
  operations: SyncOperation[],
  summary: SyncSummary,
  bestEffort: boolean,
  selector: Selector,
  sourceSnapshot: { fingerprint: string; fileCount: number },
  retainedFilePaths: Set<string>,
): CoverageWriteSummary {
  if (bestEffort) {
    for (const operation of operations) {
      try {
        applyOperation(db, operation);
        recordAppliedOperation(summary, operation);
      } catch (error) {
        recordSyncError(summary, operation.filePath, error);
      }
    }
    return skippedCoverage(selector, sourceSnapshot.fingerprint, sourceSnapshot.fileCount, "best_effort");
  }

  let currentFilePath = "";
  let coverage: CoverageWriteSummary | null = null;
  const tx = db.transaction(() => {
    for (const operation of operations) {
      currentFilePath = operation.filePath;
      applyOperation(db, operation, selector.root);
    }
    summary.removed += deleteSessionsForSelectorExceptFilePaths(db, selector, retainedFilePaths);
    const indexedSessionCount = countSessionsForSelector(db, selector);
    const record = replaceCoverage(
      db,
      selector,
      sourceSnapshot.fingerprint,
      sourceSnapshot.fileCount,
      indexedSessionCount,
      INDEX_VERSION,
    );
    coverage = {
      written: true,
      selector: record.selector,
      sourceFingerprint: record.sourceFingerprint,
      sourceFileCount: record.sourceFileCount,
      indexedSessionCount: record.indexedSessionCount,
    };
  });

  try {
    tx();
  } catch (error) {
    recordSyncError(summary, currentFilePath || "(unknown file)", error);
    throw new SyncError(summary);
  }

  for (const operation of operations) {
    recordAppliedOperation(summary, operation);
  }
  return coverage ?? skippedCoverage(selector, sourceSnapshot.fingerprint, sourceSnapshot.fileCount, "not_written");
}

function applyOperation(db: ReturnType<typeof openWriteDb>, operation: SyncOperation, sourceRoot?: string): void {
  if (operation.kind === "filtered") {
    deleteSessionByFilePath(db, operation.filePath);
    return;
  }

  replaceSession(
    db,
    operation.session,
    operation.rawFileMtime,
    operation.rawFileSize,
    INDEX_VERSION,
    operation.pathDate,
    sourceRoot,
  );
}

function retainedIndexedFilePaths(
  unchangedFilePaths: Set<string>,
  operations: SyncOperation[],
): Set<string> {
  const retained = new Set(unchangedFilePaths);
  for (const operation of operations) {
    if (operation.kind === "replace") {
      retained.add(operation.filePath);
    }
  }
  return retained;
}

function recordAppliedOperation(summary: SyncSummary, operation: SyncOperation): void {
  if (operation.kind === "filtered") {
    summary.filtered += 1;
    return;
  }

  if (operation.isUpdate) {
    summary.updated += 1;
    return;
  }

  summary.added += 1;
}

function recordSyncError(summary: SyncSummary, filePath: string, error: unknown): void {
  summary.errors += 1;
  summary.errorDetails.push({
    filePath,
    message: describeError(error),
  });
}

function describeError(error: unknown): string {
  if (error instanceof Error) return error.message;
  return String(error);
}

function buildSyncErrorMessage(summary: SyncSummary): string {
  const details = summary.errorDetails.map((detail: SyncErrorDetail) =>
    `${detail.filePath}: ${detail.message}`
  );
  return `sync failed with ${summary.errors} error(s)\n${details.join("\n")}`;
}

function skippedCoverage(
  selector: Selector,
  sourceFingerprint: string,
  sourceFileCount: number,
  reason: string,
): CoverageWriteSummary {
  return {
    written: false,
    selector,
    sourceFingerprint,
    sourceFileCount,
    indexedSessionCount: 0,
    reason,
  };
}

import { tokenizedText } from "../tokenize";
import type { ParsedSession, SessionRecord } from "../types";
import type { Db } from "./shared";
import { sessionRootFromFile } from "./sql";

export function getIndexedSessionMeta(
  db: Db,
  filePath: string,
): { rawFileMtime: number; rawFileSize: number; indexVersion: string } | null {
  const row = db
    .prepare<[string], { rawFileMtime: number; rawFileSize: number; indexVersion: string }>(`
      SELECT raw_file_mtime AS rawFileMtime, raw_file_size AS rawFileSize, index_version AS indexVersion
      FROM sessions
      WHERE file_path = ?
      LIMIT 1
    `)
    .get(filePath) as
    | { rawFileMtime: number; rawFileSize: number; indexVersion: string }
    | undefined;

  return row ?? null;
}

export function deleteSessionByFilePath(db: Db, filePath: string): void {
  const row = db
    .prepare<[string], { sessionUuid: string }>("SELECT session_uuid AS sessionUuid FROM sessions WHERE file_path = ? LIMIT 1")
    .get(filePath) as { sessionUuid: string } | undefined;

  if (!row) return;
  deleteSessionByUuid(db, row.sessionUuid);
}

export function deleteSessionByUuid(db: Db, sessionUuid: string): void {
  db.prepare("DELETE FROM sessions_fts WHERE session_uuid = ?").run(sessionUuid);
  db.prepare("DELETE FROM messages_fts WHERE session_uuid = ?").run(sessionUuid);
  db.prepare("DELETE FROM messages WHERE session_uuid = ?").run(sessionUuid);
  db.prepare("DELETE FROM sessions WHERE session_uuid = ?").run(sessionUuid);
}

export function replaceSession(
  db: Db,
  session: ParsedSession,
  rawFileMtime: number,
  rawFileSize: number,
  indexVersion: string,
  pathDate: string,
  sourceRoot = sessionRootFromFile(session.filePath),
): void {
  const tx = db.transaction(() => {
    const existing = db
      .prepare<[string, string], { id: number }>("SELECT id FROM sessions WHERE session_uuid = ? OR file_path = ? LIMIT 1")
      .get(session.sessionUuid, session.filePath) as { id: number } | undefined;

    if (existing) {
      db.prepare(
        `
          UPDATE sessions
          SET session_uuid = ?, file_path = ?, source_root = ?, title = ?, summary_text = ?, compact_text = ?, reasoning_summary_text = ?,
              cwd = ?, model = ?, started_at = ?, ended_at = ?, path_date = ?,
              message_count = ?, raw_file_mtime = ?, raw_file_size = ?, index_version = ?, updated_at = CURRENT_TIMESTAMP
          WHERE id = ?
        `,
      ).run(
        session.sessionUuid,
        session.filePath,
        sourceRoot,
        session.title,
        session.summaryText,
        session.compactText ?? "",
        session.reasoningSummaryText ?? "",
        session.cwd,
        session.model,
        session.startedAt,
        session.endedAt,
        pathDate,
        session.messages.length,
        rawFileMtime,
        rawFileSize,
        indexVersion,
        existing.id,
      );
    } else {
      db.prepare(
        `
          INSERT INTO sessions (
            session_uuid, file_path, source_root, title, summary_text, compact_text, reasoning_summary_text,
            cwd, model, started_at, ended_at, path_date,
            message_count, raw_file_mtime, raw_file_size, index_version
          ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `,
      ).run(
        session.sessionUuid,
        session.filePath,
        sourceRoot,
        session.title,
        session.summaryText,
        session.compactText ?? "",
        session.reasoningSummaryText ?? "",
        session.cwd,
        session.model,
        session.startedAt,
        session.endedAt,
        pathDate,
        session.messages.length,
        rawFileMtime,
        rawFileSize,
        indexVersion,
      );
    }

    const sessionRow = db
      .prepare<[string], { id: number }>("SELECT id FROM sessions WHERE session_uuid = ? LIMIT 1")
      .get(session.sessionUuid) as { id: number };

    db.prepare("DELETE FROM messages_fts WHERE session_uuid = ?").run(session.sessionUuid);
    db.prepare("DELETE FROM messages WHERE session_uuid = ?").run(session.sessionUuid);
    db.prepare("DELETE FROM sessions_fts WHERE rowid = ? OR session_uuid = ?").run(sessionRow.id, session.sessionUuid);

    db.prepare(
      `
        INSERT INTO sessions_fts(rowid, title, summary_text, compact_text, reasoning_summary_text, session_uuid)
        VALUES (?, ?, ?, ?, ?, ?)
      `,
    ).run(
      sessionRow.id,
      tokenizedText(session.title),
      tokenizedText(session.summaryText),
      tokenizedText(session.compactText ?? ""),
      tokenizedText(session.reasoningSummaryText ?? ""),
      session.sessionUuid,
    );

    const messageStmt = db.prepare<[number, string, number, string, string, string, string]>(`
      INSERT INTO messages (session_id, session_uuid, seq, role, content_text, timestamp, source_kind)
      VALUES (?, ?, ?, ?, ?, ?, ?)
    `);
    const ftsStmt = db.prepare<[number, string, string, number, string, string]>(`
      INSERT INTO messages_fts(rowid, content_text, session_uuid, seq, role, timestamp)
      VALUES (?, ?, ?, ?, ?, ?)
    `);

    for (const message of session.messages) {
      const result = messageStmt.run(
        sessionRow.id,
        session.sessionUuid,
        message.seq,
        message.role,
        message.contentText,
        message.timestamp,
        message.sourceKind,
      );
      const messageId = Number(result.lastInsertRowid);
      // Feed the FTS index with tokenized text so that CJK runs are split
      // into bigrams by tokenize(). Stored content in messages.content_text
      // stays raw for display.
      ftsStmt.run(
        messageId,
        tokenizedText(message.contentText),
        session.sessionUuid,
        message.seq,
        message.role,
        message.timestamp,
      );
    }
  });

  tx();
}

export function getSessionRecord(db: Db, sessionUuid: string): SessionRecord | null {
  const row = db
    .prepare<[string], SessionRecord & { filePath: string }>(`
      SELECT
        session_uuid AS sessionUuid,
        file_path AS filePath,
        source_root AS sourceRoot,
        title,
        summary_text AS summaryText,
        cwd,
        model,
        started_at AS startedAt,
        ended_at AS endedAt,
        path_date AS pathDate,
        message_count AS messageCount
      FROM sessions
      WHERE session_uuid = ?
      LIMIT 1
    `)
    .get(sessionUuid) as (SessionRecord & { filePath: string }) | undefined;

  if (!row) return null;
  return row;
}
